import './ImageGallery.scss';

import type { ImageGalleryProps } from ':components/Preview/Preview.types';
import { classNames } from ':helpers/classnames';
import React, { useEffect, useRef } from 'react';

export const ImageGallery = ({ selectedIndex, onClick, content }: ImageGalleryProps) => {
	const galleryRef = useRef<HTMLDivElement>(null);

	useEffect(() => {
		scrollIntoFrame(selectedIndex);
	}, [selectedIndex]);

	const scrollIntoFrame = index => {
		if (galleryRef.current) {
			const container = galleryRef.current;
			const selectedImg = container.children[index] as HTMLElement;

			const scrollLeft = selectedImg.offsetLeft - container.offsetWidth / 2 + selectedImg.offsetWidth / 2;

			container.scrollTo({
				left: scrollLeft,
				behavior: 'smooth',
			});
		}
	};

	const handleClickOnFrame = index => {
		onClick(index);
	};
	return (
		<div className="dsb_preview__gallery-img" ref={galleryRef}>
			{content.map((image, index) => (
				<img
					className={classNames(
						'dsb_preview__gallery-img__frame',
						selectedIndex === index && 'dsb_preview__gallery-img__frame-selected',
					)}
					key={index}
					onClick={() => handleClickOnFrame(index)}
					alt={image.alt}
					src={image.src}
				/>
			))}
		</div>
	);
};
